import { describe, expect, it } from 'vitest';

import {
  computePayloadOffset,
  parseKnotHeaderFromBytes,
  readKnotHeader,
} from '../src/knot-header';
import { buildFakeKnot, RecordingKnotSource } from './fixtures';

describe('computePayloadOffset', () => {
  it('rounds up to a 4-byte boundary then adds 1 for the codec marker', () => {
    // meta_len = 0 -> (10 + 0 + 3) & ~3 = 12, +1 = 13
    expect(computePayloadOffset(0)).toBe(13);
    // meta_len = 1 -> (10 + 1 + 3) & ~3 = 12, +1 = 13
    expect(computePayloadOffset(1)).toBe(13);
    // meta_len = 2 -> (10 + 2 + 3) & ~3 = 12, +1 = 13
    expect(computePayloadOffset(2)).toBe(13);
    // meta_len = 3 -> (10 + 3 + 3) & ~3 = 16, +1 = 17
    expect(computePayloadOffset(3)).toBe(17);
    // meta_len = 6 -> (10 + 6 + 3) & ~3 = 16, +1 = 17
    expect(computePayloadOffset(6)).toBe(17);
    // meta_len = 7 -> (10 + 7 + 3) & ~3 = 20, +1 = 21
    expect(computePayloadOffset(7)).toBe(21);
  });
});

describe('parseKnotHeaderFromBytes', () => {
  it('parses a well-formed knot header and locates the payload offset', () => {
    const knot = buildFakeKnot({ numLayers: 2 });
    const header = parseKnotHeaderFromBytes(knot.bytes);

    expect(header.version).toBe(1);
    expect(header.metadataLength).toBeGreaterThan(0);
    expect(header.payloadOffset).toBe(knot.payloadOffset);
    expect(header.metadata.tensors['token_embd_weight']).toBeDefined();
    expect(header.metadata.tensors['blk_0_attn_q_weight']).toBeDefined();
    expect(header.metadata.tensors['blk_1_ffn_down_weight']).toBeDefined();
  });

  it('rejects a non-KNOT magic', () => {
    const bogus = new Uint8Array(64);
    bogus.set(new TextEncoder().encode('NOPE'), 0);
    expect(() => parseKnotHeaderFromBytes(bogus)).toThrow(/bad magic/);
  });

  it('rejects a window smaller than the prefix', () => {
    expect(() => parseKnotHeaderFromBytes(new Uint8Array(5))).toThrow(
      /window too small/,
    );
  });

  it('rejects a window smaller than the declared metadata + codec marker', () => {
    const knot = buildFakeKnot({ numLayers: 1 });
    // Snip off everything past the prefix so the metadata is unreadable.
    const truncated = knot.bytes.subarray(0, 10);
    expect(() => parseKnotHeaderFromBytes(truncated)).toThrow(
      /window too small for metadata/,
    );
  });
});

describe('readKnotHeader', () => {
  it('reads the header in a single fetch when the initial probe is large enough', async () => {
    const knot = buildFakeKnot({ numLayers: 1 });
    const source = new RecordingKnotSource(knot.bytes);
    const header = await readKnotHeader(source, knot.bytes.length);
    expect(header.payloadOffset).toBe(knot.payloadOffset);
    expect(source.calls).toHaveLength(1);
  });

  it('issues a second fetch when the initial probe is too small', async () => {
    const knot = buildFakeKnot({ numLayers: 1 });
    const source = new RecordingKnotSource(knot.bytes);
    // First probe only big enough to read the prefix.
    const header = await readKnotHeader(source, 16);
    expect(header.payloadOffset).toBe(knot.payloadOffset);
    expect(source.calls).toHaveLength(2);
    expect(source.calls[0]?.start).toBe(0);
    expect(source.calls[0]?.end).toBe(15);
    expect(source.calls[1]?.start).toBe(0);
    expect(source.calls[1]?.end).toBe(knot.payloadOffset - 1);
  });
});
